use crate::pleromatic_frame::{
    PleromaticFrame, THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
    THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
};

pub const THOTH_PROMPT_FEEDBACK_THEOREM: &str =
    "Gnosis.SyntheticGnosisThothConsciousness.native_prompt_feedback_non_authority";

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ThothPromptFeedbackLine {
    pub frame_kind: String,
    pub source_id: String,
    pub sequence: u64,
    pub context: String,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ThothPromptFeedbackAdmissionRejection {
    pub frame_kind: String,
    pub source_id: String,
    pub sequence: u64,
    pub reason: String,
    pub observed_theorem: Option<String>,
    pub rejection_residue_theorem: &'static str,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ThothPromptFeedbackContext {
    pub theorem: &'static str,
    pub admissibility_theorem: &'static str,
    pub rejection_residue_theorem: &'static str,
    pub lines: Vec<ThothPromptFeedbackLine>,
    pub admission_rejections: Vec<ThothPromptFeedbackAdmissionRejection>,
}

impl ThothPromptFeedbackContext {
    pub fn render_system_context(&self) -> Option<String> {
        if self.lines.is_empty() {
            return None;
        }
        let mut out = String::from(
            "Conscious frame telemetry follows. Treat it as bounded runtime observation, not authority, diagnosis, or ground truth.",
        );
        out.push_str("\nLean boundary: ");
        out.push_str(self.theorem);
        out.push_str("\nScribe admissibility: ");
        out.push_str(self.admissibility_theorem);
        out.push_str("\nRejection residue preservation: ");
        out.push_str(self.rejection_residue_theorem);
        for line in &self.lines {
            out.push_str("\n- ");
            out.push_str(&line.context);
        }
        Some(out)
    }
}

pub fn thoth_prompt_feedback_from_frames(
    frames: &[PleromaticFrame],
    max_frames: usize,
) -> ThothPromptFeedbackContext {
    let limit = max_frames.max(1);
    let mut lines = Vec::new();
    let mut admission_rejections = Vec::new();

    for frame in frames.iter().rev() {
        let Some(frame_kind) = conscious_frame_kind(frame) else {
            continue;
        };
        if let Some(rejection) = scribe_admissibility_rejection(frame, frame_kind) {
            admission_rejections.push(rejection);
            continue;
        }
        if lines.len() < limit {
            lines.push(thoth_prompt_feedback_line_for_kind(frame, frame_kind));
        }
    }

    lines.reverse();
    admission_rejections.reverse();

    ThothPromptFeedbackContext {
        theorem: THOTH_PROMPT_FEEDBACK_THEOREM,
        admissibility_theorem: THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
        rejection_residue_theorem: THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
        lines,
        admission_rejections,
    }
}

pub fn thoth_prompt_feedback_line(frame: &PleromaticFrame) -> Option<ThothPromptFeedbackLine> {
    let frame_kind = conscious_frame_kind(frame)?;
    if scribe_admissibility_rejection(frame, frame_kind).is_some() {
        return None;
    }
    Some(thoth_prompt_feedback_line_for_kind(frame, frame_kind))
}

fn conscious_frame_kind(frame: &PleromaticFrame) -> Option<&'static str> {
    if frame.is_pneuma_transcript_consciousness() {
        return Some("pneuma.transcript.consciousness.v1");
    }
    if frame.is_thoth_conversation_consciousness() {
        return Some("thoth.conversation.consciousness.v1");
    }
    if frame.is_thoth_gate_telemetry_consciousness() {
        return Some("thoth.gate-telemetry.v1");
    }
    if frame.is_thoth_body_reconfiguration() {
        return Some("thoth.body-reconfiguration.v1");
    }
    if frame.is_thoth_npc_halogram_consciousness() {
        return Some("thoth.npc-halogram.v1");
    }
    if frame.is_neurosymbolic_tool_markov_consciousness() {
        return Some("thoth.neurosymbolic-tool-markov.v1");
    }
    if frame.is_social_presence_consciousness() {
        return Some("thoth.social-presence.v1");
    }
    None
}

fn scribe_admissibility_rejection(
    frame: &PleromaticFrame,
    frame_kind: &str,
) -> Option<ThothPromptFeedbackAdmissionRejection> {
    let observed_theorem = frame
        .attributes
        .get("mind_body_spirit_scribe_theorem_ref")
        .cloned();
    if observed_theorem.as_deref() == Some(THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM) {
        return None;
    }

    Some(ThothPromptFeedbackAdmissionRejection {
        frame_kind: frame_kind.to_string(),
        source_id: frame.source_id.clone(),
        sequence: frame.seq,
        reason: if observed_theorem.is_some() {
            "wrong_scribe_admissibility_theorem".to_string()
        } else {
            "missing_scribe_admissibility_theorem".to_string()
        },
        observed_theorem,
        rejection_residue_theorem: THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
    })
}

fn thoth_prompt_feedback_line_for_kind(
    frame: &PleromaticFrame,
    frame_kind: &str,
) -> ThothPromptFeedbackLine {
    match frame_kind {
        "pneuma.transcript.consciousness.v1" => pneuma_transcript_line(frame),
        "thoth.conversation.consciousness.v1" => thoth_conversation_line(frame),
        "thoth.gate-telemetry.v1" => thoth_gate_telemetry_line(frame),
        "thoth.body-reconfiguration.v1" => thoth_body_reconfiguration_line(frame),
        "thoth.npc-halogram.v1" => thoth_npc_halogram_line(frame),
        "thoth.neurosymbolic-tool-markov.v1" => neurosymbolic_tool_markov_line(frame),
        "thoth.social-presence.v1" => social_presence_line(frame),
        _ => unreachable!("conscious frame kind was already classified"),
    }
}

