    #[test]
    fn keeps_only_recent_conscious_frames() {
        let old = PleromaticFrame::pneuma_transcript_consciousness(
            "old".to_string(),
            "old-transcript".to_string(),
            "old-tag".to_string(),
            1,
            vec![],
        );
        let new = PleromaticFrame::pneuma_transcript_consciousness(
            "new".to_string(),
            "new-transcript".to_string(),
            "new-tag".to_string(),
            2,
            vec![],
        );

        let context = thoth_prompt_feedback_from_frames(&[old, new], 1);
        assert_eq!(context.lines.len(), 1);
        assert_eq!(context.lines[0].source_id, "new");
    }
